#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=2005;
int n,h,d,dp[N][N],num[N][N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>h>>d;
	for(int i=1;i<=n;i++)
	{
		int y;
		cin>>y;
		for(int j=1;j<=y;j++)
		{
			int x;
			cin>>x;
			num[i][x]++;
		}
	}
	for(int i=h;i>=1;i--)
	{
		for(int j=1;j<=n;j++)
		{
			dp[i][j]=max(dp[i+1][j],(i+d>h)?0:dp[i+d][0])+num[j][i];
			dp[i][0]=max(dp[i][0],dp[i][j]);
//			cout<<dp[i][j]<<" ";
		}
//		cout<<"\n";
	}
	cout<<dp[1][0];
	return 0;
}
